package com.oneil.wellness.walkplanner.activity;
import static org.assertj.core.api.Assertions.*;import com.oneil.wellness.walkplanner.data.HistoryExportService;import com.oneil.wellness.walkplanner.goal.*;import java.nio.charset.StandardCharsets;import java.time.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.transaction.annotation.Transactional;
@SpringBootTest @Transactional class WalkActivityIntegrationTest{
 @Autowired WalkActivityService walks;@Autowired WellnessGoalService goals;@Autowired HistoryExportService exports;
 @Test void startsRecoversCompletesAndExportsWithoutSecrets(){OffsetDateTime start=OffsetDateTime.now().plusMinutes(5);WalkActivity active=walks.start(new WalkRequest(null,start,start.plusMinutes(30),ActivitySource.DASHBOARD));assertThat(walks.active()).contains(active);assertThatThrownBy(()->walks.start(new WalkRequest(null,start,start.plusMinutes(30),ActivitySource.TIMELINE))).hasMessageContaining("already");WalkActivity completed=walks.complete(active.getId(),new CompleteWalkRequest(20,false,PerceivedQuality.RESTORATIVE,"Felt good, \"easy\" pace"));assertThat(completed.getActivityStatus()).isEqualTo(ActivityStatus.COMPLETED);assertThat(completed.getDurationMinutes()).isEqualTo(20);String csv=new String(exports.activitiesCsv(),StandardCharsets.UTF_8);assertThat(csv).contains("RESTORATIVE").contains("\"\"easy\"\"");String json=new String(exports.allJson("UTC"),StandardCharsets.UTF_8);assertThat(json).contains("\"schemaVersion\" : \"2.6\"").doesNotContain("ciphertext","refresh-token","password");}
 @Test void validatesManualWalkAndCalculatesOnlyCompletedGoalProgress(){assertThatThrownBy(()->walks.manual(new ManualWalkRequest(OffsetDateTime.now().plusHours(1),20,null,null))).hasMessageContaining("future");walks.manual(new ManualWalkRequest(OffsetDateTime.now().minusHours(2),25,PerceivedQuality.GOOD,null));goals.save(new WellnessGoalRequest(true,100,4,20,DayOfWeek.MONDAY,"UTC"));GoalProgress progress=goals.progress();assertThat(progress.walkingMinutes()).isEqualTo(25);assertThat(progress.completedWalks()).isEqualTo(1);assertThat(progress.remainingMinutes()).isEqualTo(75);}
}
